INSERT INTO tb_menu
(
	 menu_seq
	,up_menu_seq
	,menu_nm
	,menu_type_cd
	,menu_view_path
	,menu_url
	,use_yn
	,sort_seq
	,rgst_user_seq
	,rgst_date_time
	,upt_user_seq
	,upt_date_time
)
VALUES (
	 (SELECT coalesce(max(menu_seq), 0)+1 FROM tb_menu)
	 ,#{upMenuId}
	 ,#{menuNm}
	 ,#{menuTypeCd}
	 ,#{menuViewPath}
	 ,#{menuUri}
	 ,#{useFlag}
	 ,#{sortSeq}
	 ,#{rgstUserId}
	 ,now()
	 ,#{uptUserId}
	 ,now()
)

mapper.update:
UPDATE tb_menu
SET
	 up_menu_seq = #{upMenuId}
	,menu_nm = #{menuNm}
	,menu_type_cd = #{menuTypeCd}
	,menu_view_path = #{menuViewPath}
	,menu_url = #{menuUri}
	,use_yn = #{useFlag}
	,sort_seq = #{sortSeq}
	,upt_user_seq = #{uptUserId}
	,upt_date_time = now()
WHERE menu_seq = #{menuSeq}
